'use client';

import React, { useEffect, useState } from 'react';
import { Bell, Package, Truck, MessageSquare } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
//import { toast } from 'sonner'; // optional: for real-time feel
// import io from 'socket.io-client';
// import axios from 'axios';

// const socket = io('http://localhost:4000'); // 🟡 for real-time in future

interface Notification {
  _id: string;
  type: 'order' | 'delivery' | 'review';
  message: string;
  createdAt: string;
  isRead: boolean;
}

export default function NotificationsPage() {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    // 🧠 Dummy Data for now
    const dummyData: Notification[] = [
      {
        _id: '1',
        type: 'order',
        message: 'New order received from Riya Sharma',
        createdAt: new Date().toISOString(),
        isRead: false,
      },
      {
        _id: '2',
        type: 'delivery',
        message: 'Order #102 delivered successfully',
        createdAt: new Date(Date.now() - 3600000).toISOString(),
        isRead: false,
      },
      {
        _id: '3',
        type: 'review',
        message: 'Rahul posted a new review: "Amazing plant quality!"',
        createdAt: new Date(Date.now() - 7200000).toISOString(),
        isRead: true,
      },
    ];

    setNotifications(dummyData);
    setUnreadCount(dummyData.filter(n => !n.isRead).length);

    // 🟢 Real API Call (Future)
    // const token = localStorage.getItem('token');
    // axios.get('/api/notifications', {
    //   headers: { Authorization: `Bearer ${token}` },
    // }).then(res => {
    //   setNotifications(res.data);
    //   setUnreadCount(res.data.filter(n => !n.isRead).length);
    // });

    // 🟢 Real-time socket listener
    // socket.on('newNotification', (notif: Notification) => {
    //   toast.success(`🔔 ${notif.message}`);
    //   setNotifications(prev => [notif, ...prev]);
    //   setUnreadCount(prev => prev + 1);
    // });

    // return () => socket.off('newNotification');
  }, []);

  const handleMarkAsRead = (id: string) => {
    setNotifications(prev =>
      prev.map(n => (n._id === id ? { ...n, isRead: true } : n))
    );
    setUnreadCount(prev => (prev > 0 ? prev - 1 : 0));

    // 🔹 Replace with real API call
    // axios.put(`/api/notifications/${id}`, { isRead: true });
  };

  const getIcon = (type: string) => {
    switch (type) {
      case 'order':
        return <Package className="text-blue-600" size={18} />;
      case 'delivery':
        return <Truck className="text-green-600" size={18} />;
      case 'review':
        return <MessageSquare className="text-yellow-600" size={18} />;
      default:
        return <Bell size={18} />;
    }
  };

  return (
    <div className="p-6 md:p-10 min-h-screen bg-linear-to-br from-gray-50 to-gray-100">
      {/* Header Section */}
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl md:text-3xl font-bold flex items-center gap-2">
          <Bell size={26} className="text-indigo-600" />
          Notifications
        </h1>

        {/* Notification Bell with Badge */}
        <div className="relative">
          <Button variant="outline" size="icon" className="rounded-full bg-white shadow-sm">
            <Bell size={22} className="text-gray-700" />
            {unreadCount > 0 && (
              <span className="absolute -top-1 -right-1 bg-red-600 text-white text-xs font-bold px-1.5 py-0.5 rounded-full">
                {unreadCount}
              </span>
            )}
          </Button>
        </div>
      </div>

      <Separator className="mb-4" />

      {/* Notification List */}
      <div className="space-y-4">
        {notifications.length === 0 && (
          <p className="text-gray-500 text-center mt-20">No notifications yet 📭</p>
        )}

        {notifications.map((notif) => (
          <Card
            key={notif._id}
            className={`transition-all hover:shadow-md ${
              notif.isRead ? 'bg-white' : 'bg-indigo-50'
            }`}
          >
            <CardHeader className="flex flex-row items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-gray-100 rounded-full">{getIcon(notif.type)}</div>
                <div>
                  <CardTitle className="text-base font-semibold text-gray-800">
                    {notif.message}
                  </CardTitle>
                  <p className="text-xs text-gray-500 mt-1">
                    {new Date(notif.createdAt).toLocaleString()}
                  </p>
                </div>
              </div>

              {!notif.isRead && (
                <Badge variant="outline" className="bg-red-100 text-red-600 border-red-200">
                  New
                </Badge>
              )}
            </CardHeader>

            <CardContent className="flex justify-end">
              {!notif.isRead ? (
                <Button
                  size="sm"
                  variant="secondary"
                  onClick={() => handleMarkAsRead(notif._id)}
                  className="bg-indigo-600 hover:bg-indigo-700 text-white"
                >
                  Mark as Read
                </Button>
              ) : (
                <Button
                  size="sm"
                  variant="outline"
                  className="text-gray-600"
                  disabled
                >
                  Read
                </Button>
              )}
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}
